    <script>

        function ShowCorrectionAmount(e)
        {
            e.target.value = e.target.value.replace(/,/g, '.');

           // if (e.target.value.indexOf('.') == -1) { return; }
           // if ((e.target.value.length - e.target.value.indexOf('.')) > 2) {
           //     e.target.value = parseFloat(e.target.value).toFixed(2);
           // }

            if (e.target.value == 0)
                document.getElementById('final-correction').innerHTML = ""0.00""
            else {
                var total = document.getElementById('total-sum').innerHTML;
                var val = e.target.value - total.replace(/,/g, '.');

                document.getElementById('final-correction').innerHTML = parseFloat(val).toFixed(2)
            }
        }

        $($("".filter-row"")[0]).css(""width"", $(""#lica-table"").width() + 34);

        $(window).resize(function () {
            $($("".filter-row"")[0]).css(""width"", $(""#lica-table"").width() + 34);
        });

